  KEY `idx_irn` (`IRN`),
  KEY `idx_ewb` (`EWBNumber`),
  CONSTRAINT `fk_einv_dc` FOREIGN KEY (`DCID`) REFERENCES `pk_deliverychallans` (`DCID`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Per-DC e-invoice + e-way-bill log. CancelledAt IS NULL = active record.';
