CREATE DEFINER=`root`@`localhost` PROCEDURE `usp_GetCitiesByState`(IN p_StateID INT, IN p_Days INT)
BEGIN
    SELECT
        c.CityID,
        c.CityName,
        IFNULL(SUM(so.TotalValue), 0) AS TotalSales
    FROM Cities c
    JOIN Distributors d ON d.CityID                  = c.CityID
    JOIN SalesOrders so ON UPPER(so.DistributorName) = UPPER(d.DistributorName)
    WHERE c.StateID = p_StateID
      AND so.OrderDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
    GROUP BY c.CityID, c.CityName
    HAVING IFNULL(SUM(so.TotalValue), 0) > 0
    ORDER BY TotalSales DESC;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
