CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetDailySalesReport`(
    IN p_From DATE,
    IN p_To   DATE
)
BEGIN
    SELECT
        so.OrderDate,
        so.ProductName,
        SUM(so.NoOfUnits)   AS TotalUnits,
        SUM(so.TotalValue)  AS TotalValue
    FROM SalesOrders so
    WHERE so.OrderDate BETWEEN p_From AND p_To
    GROUP BY so.OrderDate, so.ProductName
    ORDER BY so.OrderDate, so.ProductName;
END ;;
DELIMITER ;
