CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetDistributorCreditSummary`(IN p_DistributorID INT, IN p_Days INT)
BEGIN
    SELECT
        IFNULL(SUM(CreditAmount), 0) AS CreditTotal,
        IFNULL(SUM(CASE WHEN ReceiptDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
                        THEN CreditAmount ELSE 0 END), 0) AS Credit60Days,
        (SELECT IFNULL(SUM(TotalValue), 0) FROM SalesOrders
         WHERE DistributorID = p_DistributorID) AS SalesTotal,
        MAX(ReceiptDate) AS LastPaymentDate,
        (SELECT CreditAmount FROM ReceiptRegister
         WHERE DistributorID = p_DistributorID
         ORDER BY ReceiptDate DESC LIMIT 1) AS LastPaymentAmt
    FROM ReceiptRegister
    WHERE DistributorID = p_DistributorID;
END ;;
DELIMITER ;
