CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetDistributorOrderHistory`(
    IN p_DistributorID INT,
    IN p_Days INT
)
BEGIN
    SELECT 
        OrderDate,
        SUM(NoOfUnits) AS NoOfUnits,
        SUM(TotalValue) AS TotalValue
    FROM SalesOrders
    WHERE DistributorID = p_DistributorID
      AND OrderDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
    GROUP BY OrderDate
    ORDER BY OrderDate ASC;
END ;;
