CREATE DEFINER=`root`@`localhost` PROCEDURE `usp_GetDistributorPaymentHistory`(IN p_DistributorID INT, IN p_Days INT)
BEGIN
    DECLARE v_DistributorName VARCHAR(255);
    SELECT DistributorName INTO v_DistributorName
    FROM Distributors WHERE DistributorID = p_DistributorID LIMIT 1;

    SELECT ReceiptDate, CreditAmount, VchNo
    FROM ReceiptRegister
    WHERE UPPER(Particulars) = UPPER(v_DistributorName)
      AND ReceiptDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
    ORDER BY ReceiptDate ASC;
END ;;
DELIMITER ;
