DELIMITER ;;
CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetDistributorSalesSummary`(IN p_DistributorID INT, IN p_Days INT)
BEGIN
    SELECT
        COUNT(DISTINCT InvoiceNo)   AS TotalOrders,
        IFNULL(SUM(NoOfUnits), 0)   AS TotalUnits,
        IFNULL(SUM(TotalValue), 0)  AS TotalValue,
        MAX(OrderDate)              AS LastOrderDate
    FROM SalesOrders
    WHERE DistributorID = p_DistributorID
      AND OrderDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY);
END ;;
DELIMITER ;
