/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `usp_GetDistributorsByCity`(IN p_CityID INT, IN p_Days INT)
BEGIN
    SELECT
        d.DistributorID,
        d.DistributorName,
        IFNULL(s.RecentValue, 0) AS RecentValue
    FROM Distributors d
    LEFT JOIN (
        SELECT
            UPPER(DistributorName)  AS DistNameUpper,
            SUM(TotalValue)         AS RecentValue
        FROM SalesOrders
        WHERE OrderDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
        GROUP BY UPPER(DistributorName)
    ) s ON UPPER(d.DistributorName) = s.DistNameUpper
    WHERE d.CityID = p_CityID
      AND d.DistributorName NOT LIKE '%SAMPLES%'
      AND d.DistributorName NOT LIKE '% EMP%'
      AND d.DistributorName NOT LIKE 'EMP %'
      AND d.DistributorID IN (
            SELECT d2.DistributorID
            FROM Distributors d2
            JOIN SalesOrders so ON UPPER(so.DistributorName) = UPPER(d2.DistributorName)
            WHERE d2.CityID = p_CityID
            GROUP BY d2.DistributorID
            HAVING SUM(so.TotalValue) >= 10000
      )
    ORDER BY IFNULL(s.RecentValue, 0) DESC, d.DistributorName ASC;
END ;;
DELIMITER ;
