DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `usp_GetStates`(IN p_Days INT)
BEGIN
    SELECT
        s.StateID,
        s.StateName,
        IFNULL(SUM(so.TotalValue), 0) AS TotalSales
    FROM States s
    JOIN Cities c       ON c.StateID                 = s.StateID
    JOIN Distributors d ON d.CityID                  = c.CityID
    JOIN SalesOrders so ON UPPER(so.DistributorName) = UPPER(d.DistributorName)
    WHERE so.OrderDate >= DATE_SUB(CURDATE(), INTERVAL p_Days DAY)
    GROUP BY s.StateID, s.StateName
    HAVING IFNULL(SUM(so.TotalValue), 0) >= 100000
    ORDER BY TotalSales DESC;
END ;;
DELIMITER ;
