DELIMITER ;;
CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetStockMovementClosing`(
    IN p_From     DATE,
    IN p_To       DATE,
    IN p_StateID  INT,
    IN p_CityID   INT,
    IN p_DistID   INT
)
BEGIN
    SELECT
        sp.DistributorID,
        d.DistributorName,
        sp.EntryDate,
        sp.CurrentStock
    FROM StockPositions sp
    JOIN Distributors d ON d.DistributorID = sp.DistributorID
    JOIN Cities       c ON c.CityID        = d.CityID
    WHERE DATE(sp.EntryDate) BETWEEN p_From AND p_To
      AND (p_StateID = 0 OR c.StateID        = p_StateID)
      AND (p_CityID  = 0 OR d.CityID         = p_CityID)
      AND (p_DistID  = 0 OR sp.DistributorID = p_DistID)
    ORDER BY sp.DistributorID, sp.EntryDate;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
