CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `usp_GetStockMovementPurchases`(
    IN p_From     DATE,
    IN p_To       DATE,
    IN p_StateID  INT,
    IN p_CityID   INT,
    IN p_DistID   INT
)
BEGIN
    SELECT
        so.DistributorID,
        d.DistributorName,
        so.OrderDate,
        so.InvoiceNo,
        so.ProductName,
        so.NoOfUnits
    FROM SalesOrders so
    JOIN Distributors d ON d.DistributorID = so.DistributorID
    JOIN Cities       c ON c.CityID        = d.CityID
    WHERE so.OrderDate BETWEEN p_From AND p_To
      AND (p_StateID = 0 OR c.StateID      = p_StateID)
      AND (p_CityID  = 0 OR d.CityID       = p_CityID)
      AND (p_DistID  = 0 OR so.DistributorID = p_DistID)
    ORDER BY so.DistributorID, so.OrderDate, so.InvoiceNo;
END ;;
