CREATE DEFINER=`root`@`localhost` PROCEDURE `usp_SaveStockPosition`(
    IN p_StateID      INT,
    IN p_CityID       INT,
    IN p_DistributorID INT,
    IN p_CurrentStock INT
)
BEGIN
    INSERT INTO StockPositions (StateID, CityID, DistributorID, CurrentStock, EntryDate)
    VALUES (p_StateID, p_CityID, p_DistributorID, p_CurrentStock, NOW());
    SELECT LAST_INSERT_ID() AS NewID;
END ;;
