INSERT INTO `fin_chartofaccounts` VALUES (1,'3720966000000000468','Advance Tax',NULL,'other_current_asset',NULL,NULL,'Any tax which is paid in advance is recorded into the advance tax account. This advance tax payment could be a quarterly, half yearly or yearly payment.',1,'2026-04-24 08:52:13','2026-04-20 00:52:00'),(2,'3720966000000032331','Input Tax Credits',NULL,'other_current_asset',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:00'),(3,'3720966000000032351','Input SGST',NULL,'other_current_asset',NULL,'3720966000000032331',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(4,'3720966000000032343','Input CGST',NULL,'other_current_asset',NULL,'3720966000000032331',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(5,'3720966000000032335','Input IGST',NULL,'other_current_asset',NULL,'3720966000000032331',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(6,'3720966000000032313','Reverse Charge Tax Input but not due',NULL,'other_current_asset',NULL,NULL,'The amount of tax payable for your reverse charge purchases can be tracked here.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(7,'3720966000000032028','TDS Receivable',NULL,'other_current_asset',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(8,'3720966000000032022','Prepaid Expenses',NULL,'other_current_asset',NULL,NULL,'An asset account that reports amounts paid in advance while purchasing goods or services from a vendor.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(9,'3720966000000000570','Employee Advance',NULL,'other_current_asset',NULL,NULL,'Money paid out to an employee in advance can be tracked here till it\'s repaid or shown to be spent for company purposes.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(10,'3720966000000000459','Petty Cash',NULL,'cash',NULL,NULL,'It is a small amount of cash that is used to pay your minor or casual expenses rather than writing a check.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(11,'3720966000000000456','Undeposited Funds',NULL,'cash',NULL,NULL,'Record funds received by your company yet to be deposited in a bank as undeposited funds and group them as a current asset in your balance sheet.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(12,'3720966000000000462','Accounts Receivable',NULL,'accounts_receivable',NULL,NULL,'The money that customers owe you becomes the accounts receivable. A good example of this is a payment expected from an invoice sent to your customer.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(13,'3720966000000000465','Furniture and Equipment',NULL,'fixed_asset',NULL,NULL,'Purchases of furniture and equipment for your office that can be used for a long period of time usually exceeding one year can be tracked with this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(14,'3720966000000000615','Opening Balance Adjustments',NULL,'other_current_liability',NULL,NULL,'This account will hold the difference in the debits and credits entered during the opening balance.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(15,'3720966000000032323','GST Payable',NULL,'other_current_liability',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(16,'3720966000000032347','Output SGST',NULL,'other_current_liability',NULL,'3720966000000032323',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(17,'3720966000000032339','Output CGST',NULL,'other_current_liability',NULL,'3720966000000032323',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(18,'3720966000000032327','Output IGST',NULL,'other_current_liability',NULL,'3720966000000032323',NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(19,'3720966000000000474','Tax Payable',NULL,'other_current_liability',NULL,NULL,'The amount of money which you owe to your tax authority is recorded under the tax payable account. This amount is a sum of your outstanding in taxes and the tax charged on sales.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(20,'3720966000000032032','TDS Payable',NULL,'other_current_liability',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(21,'3720966000000000617','Unearned Revenue',NULL,'other_current_liability',NULL,NULL,'A liability account that reports amounts received in advance of providing goods or services. When the goods or services are provided, this account balance is decreased and a revenue account is increased.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(22,'3720966000000000573','Employee Reimbursements',NULL,'other_current_liability',NULL,NULL,'This account can be used to track the reimbursements that are due to be paid out to employees.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(23,'3720966000000000471','Accounts Payable',NULL,'accounts_payable',NULL,NULL,'This is an account of all the money which you owe to others like a pending bill payment to a vendor,etc.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(24,'3720966000000032072','Mortgages',NULL,'long_term_liability',NULL,NULL,'An expense account that tracks the amounts you pay for the mortgage loan.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(25,'3720966000000032074','Construction Loans',NULL,'long_term_liability',NULL,NULL,'An expense account that tracks the amount you repay for construction loans.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(26,'3720966000000000579','Dimension Adjustments',NULL,'other_liability',NULL,NULL,'This adjustment account tracks the transfers between different dimensions like tags, branches.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(27,'3720966000000032090','Dividends Paid',NULL,'equity',NULL,NULL,'An equity account to track the dividends paid when a corporation declares dividend on its common stock.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(28,'3720966000000032088','Capital Stock',NULL,'equity',NULL,NULL,'An equity account that tracks the capital introduced when a business is operated through a company or corporation.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(29,'3720966000000032078','Distributions',NULL,'equity',NULL,NULL,'An equity account that tracks the payment of stock, cash or physical products to its shareholders.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(30,'3720966000000032076','Investments',NULL,'equity',NULL,NULL,'An equity account used to track the amount that you invest.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(31,'3720966000000000477','Retained Earnings',NULL,'equity',NULL,NULL,'The earnings of your company which are not distributed among the share holders is accounted as retained earnings.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(32,'3720966000000000480','Owner\'s Equity',NULL,'equity',NULL,NULL,'The owners rights to the assets of a company can be quantified in the owner\'\'s equity account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(33,'3720966000000000561','Drawings',NULL,'equity',NULL,NULL,'The money withdrawn from a business by its owner can be tracked with this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(34,'3720966000000000483','Opening Balance Offset',NULL,'equity',NULL,NULL,'This is an account where you can record the balance from your previous years earning or the amount set aside for some activities. It is like a buffer account for your funds.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(35,'3720966000000000504','Discount',NULL,'income',NULL,NULL,'Any reduction on your selling price as a discount can be recorded into the discount account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(36,'3720966000000000495','Late Fee Income',NULL,'income',NULL,NULL,'Any late fee income is recorded into the late fee income account. The late fee is levied when the payment for an invoice is not received by the due date.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(37,'3720966000000000492','Interest Income',NULL,'income',NULL,NULL,'A percentage of your balances and deposits are given as interest to you by your banks and financial institutions. This interest is recorded into the interest income account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(38,'3720966000000000622','Shipping Charge',NULL,'income',NULL,NULL,'Shipping charges made to the invoice will be recorded in this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(39,'3720966000000000619','Other Charges',NULL,'income',NULL,NULL,'Miscellaneous charges like adjustments made to the invoice can be recorded in this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(40,'3720966000000000486','Sales',NULL,'income',NULL,NULL,'The income from the sales in your business is recorded under the sales account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(41,'3720966000000000489','General Income',NULL,'income',NULL,NULL,'A general category of account where you can record any income which cannot be recorded into any other category.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(42,'3720966000000000507','Bank Fees and Charges',NULL,'expense',NULL,NULL,'Any bank fees levied is recorded into the bank fees and charges account. A bank account maintenance fee, transaction charges, a late payment fee are some examples.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(43,'3720966000000000540','Printing and Stationery',NULL,'expense',NULL,NULL,'Expenses incurred by the organization towards printing and stationery.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(44,'3720966000000000537','Bad Debt',NULL,'expense',NULL,NULL,'Any amount which is lost and is unrecoverable is recorded into the bad debt account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(45,'3720966000000032092','Raw Materials And Consumables',NULL,'expense',NULL,NULL,'An expense account to track the amount spent on purchasing raw materials and consumables.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(46,'3720966000000032094','Merchandise',NULL,'expense',NULL,NULL,'An expense account to track the amount spent on purchasing merchandise.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(47,'3720966000000032096','Transportation Expense',NULL,'expense',NULL,NULL,'An expense account to track the amount spent on transporting goods or providing services.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(48,'3720966000000032098','Depreciation And Amortisation',NULL,'expense',NULL,NULL,'An expense account that is used to track the depreciation of tangible assets and intangible assets, which is amortization.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(49,'3720966000000032100','Contract Assets',NULL,'expense',NULL,NULL,'An asset account to track the amount that you receive from your customers while you\'re yet to complete rendering the services.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(50,'3720966000000000510','Credit Card Charges',NULL,'expense',NULL,NULL,'Service fees for transactions , balance transfer fees, annual credit fees and other charges levied on a credit card are recorded into the credit card account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(51,'3720966000000000519','Telephone Expense',NULL,'expense',NULL,NULL,'The expenses on your telephone, mobile and fax usage are accounted as telephone expenses.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(52,'3720966000000000534','Postage',NULL,'expense',NULL,NULL,'Your expenses on ground mails, shipping and air mails can be recorded under the postage account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(53,'3720966000000000531','Janitorial Expense',NULL,'expense',NULL,NULL,'All your janitorial and cleaning expenses are recorded into the janitorial expenses account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(54,'3720966000000000501','Advertising And Marketing',NULL,'expense',NULL,NULL,'Your expenses on promotional, marketing and advertising activities like banners, web-adds, trade shows, etc. are recorded in advertising and marketing account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(55,'3720966000000000498','Office Supplies',NULL,'expense',NULL,NULL,'All expenses on purchasing office supplies like stationery are recorded into the office supplies account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(56,'3720966000000000528','Rent Expense',NULL,'expense',NULL,NULL,'The rent paid for your office or any space related to your business can be recorded as a rental expense.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(57,'3720966000000000525','IT and Internet Expenses',NULL,'expense',NULL,NULL,'Money spent on your IT infrastructure and usage like  internet connection, purchasing computer equipment etc is recorded as an IT and Computer Expense.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(58,'3720966000000000522','Automobile Expense',NULL,'expense',NULL,NULL,'Transportation related expenses like fuel charges and maintenance charges for automobiles, are included to the automobile expense account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(59,'3720966000000000576','Uncategorized',NULL,'expense',NULL,NULL,'This account can be used to temporarily track expenses that are yet to be identified and classified into a particular category.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(60,'3720966000000000516','Travel Expense',NULL,'expense',NULL,NULL,'Expenses on business travels like hotel bookings, flight charges, etc. are recorded as travel expenses.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(61,'3720966000000000543','Salaries and Employee Wages',NULL,'expense',NULL,NULL,'Salaries for your employees and the wages paid to workers are recorded under the salaries and wages account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(62,'3720966000000000546','Meals and Entertainment',NULL,'expense',NULL,NULL,'Expenses on food and entertainment are recorded into this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(63,'3720966000000000549','Depreciation Expense',NULL,'expense',NULL,NULL,'Any depreciation in value of your assets can be captured as a depreciation expense.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(64,'3720966000000000552','Consultant Expense',NULL,'expense',NULL,NULL,'Charges for availing the services of a consultant is recorded as a consultant expenses. The fees paid to a soft skills consultant to impart personality development training for your employees is a good example.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(65,'3720966000000000564','Lodging',NULL,'expense',NULL,NULL,'Any expense related to putting up at motels etc while on business travel can be entered here.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(66,'3720966000000000555','Repairs and Maintenance',NULL,'expense',NULL,NULL,'The costs involved in maintenance and repair of assets is recorded under this account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(67,'3720966000000000558','Other Expenses',NULL,'expense',NULL,NULL,'Any minor expense on activities unrelated to primary business operations is recorded under the other expense account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(68,'3720966000000011001','Purchase Discounts',NULL,'expense',NULL,NULL,'Tracks any reduction that your vendor offers on your purchases. Some vendors also provide them to encourage quick payment settlement.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(69,'3720966000000032084','Subcontractor',NULL,'cost_of_goods_sold',NULL,NULL,'An expense account to track the amount that you pay subcontractors who provide service to you.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(70,'3720966000000000567','Cost of Goods Sold',NULL,'cost_of_goods_sold',NULL,NULL,'An expense account which tracks the value of the goods sold.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(71,'3720966000000032080','Labor',NULL,'cost_of_goods_sold',NULL,NULL,'An expense account that tracks the amount that you pay as labor.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(72,'3720966000000032082','Materials',NULL,'cost_of_goods_sold',NULL,NULL,'An expense account that tracks the amount you use in purchasing materials.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(73,'3720966000000032086','Job Costing',NULL,'cost_of_goods_sold',NULL,NULL,'An expense account to track the costs that you incur in performing a job or a task.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(74,'3720966000000000513','Exchange Gain or Loss',NULL,'other_expense',NULL,NULL,'Changing the conversion rate can result in a gain or a loss. You can record this into the exchange gain or loss account.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(75,'3720966000000000626','Inventory Asset',NULL,'stock',NULL,NULL,'An account which tracks the value of goods in your inventory.',1,'2026-04-24 08:52:13','2026-04-20 00:52:01'),(162,'3720966000000185031','CUB CCOD Account','CCOD_CUB_1','bank',NULL,NULL,'CCOD Account',0,'2026-04-24 08:52:13','2026-04-20 22:06:26'),(239,'3720966000000206002','YES BANK FDOD','FREEDOMFLEXI25','bank',NULL,NULL,'Current Account with FD Deposit',1,'2026-04-24 08:52:13','2026-04-23 12:01:51'),(240,'3720966000000206007','CUB_CCOD_Account','CCOD-512020010036433','bank',NULL,NULL,'CGTMSE CCOD Account',1,'2026-04-24 08:52:13','2026-04-23 12:01:51'),(241,'3720966000000206012','UCO Bank Current Account','C00422870','bank',NULL,NULL,'Current',1,'2026-04-24 08:52:13','2026-04-23 12:01:51'),(242,'3720966000000206017','IOB_Current_Account','CDPUB-GOLD','bank',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-23 12:01:51'),(243,'3720966000000206024','CUB CURRENT Account','8259120','bank',NULL,NULL,NULL,1,'2026-04-24 08:52:13','2026-04-23 12:01:51');
